+	// v2: description must be a plain string.
+	desc, ok := fields["description"].(string)
+	if !ok {
+		t.Fatalf("v2 description type = %T, want string", fields["description"])
+	}
+	if desc != "Hello world" {
+		t.Errorf("v2 description = %q, want %q", desc, "Hello world")
+	}
+}
